import React from "react";
import styled from "@emotion/styled";
import ProfileImage from "./ProfileImage";
import TypeIt from "typeit-react";
import DatePicker from "./DatePicker";

const Background = styled.div`
  width: 100%;
  background-color: #000;
  color: #ffffff;
  margin-top: 2rem;
`;

const Wrapper = styled.div`
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: flex-start;
  width: 768px;
  height: 400px;
  margin: 0 auto;

  @media (max-width: 768px) {
    width: 100%;
    height: 200px;
    padding: 0 20px;
    margin-top: 60px;
  }
`;

const Main = styled.div`
  width: 100%;
  display: flex;
  justify-content: space-between;
  align-items: center;

  @media (max-width: 768px) {
    gap: 3rem;
  }
`;

const FirstColumn = styled.div`
  padding: 1rem 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
`;

const LinkIcon = styled.ul`
  display: flex;
  gap: 1rem;
  font-size: 20px;
  padding: 5px;
  width: 100%;
  justify-content: space-evenly;
`;

const TitleWrapper = styled.div`
  display: flex;
  justify-content: center;
  align-items: center;
  gap: 2rem;
  margin-top: 5px;
  font-size: 38px;
  font-weight: 700;

  @media (max-width: 768px) {
    font-size: 25px;
  }
`;

const Introduction = ({ profileImage, typeIt, edges, datePicker }) => {
  return (
    <Background>
      <Wrapper>
        <Main>
          <ProfileImage profileImage={profileImage} />
          {datePicker ? <DatePicker edges={edges}></DatePicker> : false}
        </Main>
        <TitleWrapper>
          {typeIt ? (
            <TypeIt
              options={{ speed: 30 }}
              getBeforeInit={(instance) => {
                instance.type("Playground for FE Developers that I make").pause(500).delete(40).pause(500).type("Flayground");
                // Remember to return it!
                return instance;
              }}
            />
          ) : (
            false
          )}
        </TitleWrapper>
      </Wrapper>
    </Background>
  );
};

export default Introduction;
